export function Logo({
  className = "",
  compactOnMobile = true,
  size,
}: {
  className?: string;
  compactOnMobile?: boolean;
  size?: "default" | "compact";
}) {
  const defaultLogo = (
    <svg
      viewBox="0 0 118 25"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      className="block h-[25px] w-[118px]"
      aria-hidden="true"
    >
      <path d={MARK_PATH} fill="#DB38F0" transform="translate(0.472 0.06)" />
      <path
        d={MARK_INNER_PATH}
        fill="#00FFFF"
        transform="translate(11.02 3.265)"
      />
      <path
        d={WORDMARK_PATH}
        fill="#E600F4"
        transform="translate(35.13 2.855)"
      />
    </svg>
  );

  const compactLogo = (
    <svg
      viewBox="0 0 32 25"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      className="block h-[25px] w-[32px]"
      aria-hidden="true"
    >
      <path d={MARK_PATH} fill="#DB38F0" transform="translate(0.467 0.06)" />
      <path
        d={MARK_INNER_PATH}
        fill="#00FFFF"
        transform="translate(11.024 3.265)"
      />
    </svg>
  );

  return (
    <div className={className} role="img" aria-label="Hexoo">
      {size === "compact" ? compactLogo : null}
      {size === "default" ? defaultLogo : null}
      {!size ? (
        <>
          <div className={compactOnMobile ? "hidden sm:block" : "block"}>
            {defaultLogo}
          </div>
          {compactOnMobile ? (
            <div className="sm:hidden">{compactLogo}</div>
          ) : null}
        </>
      ) : null}
    </div>
  );
}
